import { useState } from "react";

function Login() {
  const [role, setRole] = useState("manager");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log({ role, email, password });
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-100">
      
      <div className="bg-white w-[400px] p-8 rounded-2xl shadow-lg">

        {/* Title */}
        <h2 className="text-2xl font-semibold mb-1 text-gray-900">
          Inventra
        </h2>
        <p className="text-gray-500 text-sm mb-6">
          Sign in to manage inventory
        </p>

        {/* Role Selection */}
        <div className="mb-6">
          <p className="text-xs text-gray-400 mb-2 uppercase">
            Your Role
          </p>

          <div className="flex gap-3">
            <button
              onClick={() => setRole("manager")}
              className={`flex-1 p-3 rounded-xl border ${
                role === "manager"
                  ? "border-blue-500 bg-blue-50 text-blue-600"
                  : "border-gray-200"
              }`}
            >
              Manager
            </button>

            <button
              onClick={() => setRole("staff")}
              className={`flex-1 p-3 rounded-xl border ${
                role === "staff"
                  ? "border-blue-500 bg-blue-50 text-blue-600"
                  : "border-gray-200"
              }`}
            >
              Staff
            </button>
          </div>
        </div>

        {/* Email */}
        <div className="mb-4">
          <p className="text-xs text-gray-400 mb-1">Email</p>
          <input
            type="email"
            placeholder="Enter email"
            className="w-full p-3 border rounded-xl outline-none focus:border-blue-500"
            onChange={(e) => setEmail(e.target.value)}
          />
        </div>

        {/* Password */}
        <div className="mb-5">
          <p className="text-xs text-gray-400 mb-1">Password</p>
          <input
            type="password"
            placeholder="Enter password"
            className="w-full p-3 border rounded-xl outline-none focus:border-blue-500"
            onChange={(e) => setPassword(e.target.value)}
          />
        </div>

        {/* Button */}
        <button
          onClick={handleSubmit}
          className="w-full bg-black text-white p-3 rounded-xl hover:bg-gray-900"
        >
          Sign in →
        </button>

      </div>
    </div>
  );
}

export default Login;
